SAMPLE_RESULTS = {
    "total_routes": {
        "description": "Total routes",
        "value":       47,
        "status":      "ok",
        "operation":   "sum"
    },
    "total_vrfs": {
        "description": "Total VRFs",
        "value":       1,
        "status":      "ok",
        "operation":   "count"
    }
}


def test_build_json_output_structure():
    data = build_json_output("n7k", "nxos", SAMPLE_RESULTS)
    assert data["router"]    == "n7k"
    assert data["os"]        == "nxos"
    assert "timestamp"       in data
    assert "kpis"            in data
    assert "total_routes"    in data["kpis"]
    assert "total_vrfs"      in data["kpis"]


def test_build_json_output_kpi_fields():
    data = build_json_output("n7k", "nxos", SAMPLE_RESULTS)
    kpi  = data["kpis"]["total_routes"]
    assert kpi["value"]     == 47
    assert kpi["status"]    == "ok"
    assert kpi["operation"] == "sum"
    assert "description"    in kpi


def test_build_json_output_timestamp_format():
    data = build_json_output("n7k", "nxos", SAMPLE_RESULTS)
    from datetime import datetime
    datetime.fromisoformat(data["timestamp"])


def test_write_json_output_creates_file(tmp_path):
    filepath = str(tmp_path / "output.json")
    data     = build_json_output("n7k", "nxos", SAMPLE_RESULTS)
    write_json_output(data, filepath, VERBOSITY_SILENT)
    assert os.path.exists(filepath)


def test_write_json_output_valid_json(tmp_path):
    filepath = str(tmp_path / "output.json")
    data     = build_json_output("n7k", "nxos", SAMPLE_RESULTS)
    write_json_output(data, filepath, VERBOSITY_SILENT)
    with open(filepath) as f:
        loaded = json.load(f)
    assert loaded["router"] == "n7k"
    assert loaded["os"]     == "nxos"
    assert len(loaded["kpis"]) == 2


def test_write_json_output_correct_values(tmp_path):
    filepath = str(tmp_path / "output.json")
    data     = build_json_output("n7k", "nxos", SAMPLE_RESULTS)
    write_json_output(data, filepath, VERBOSITY_SILENT)
    with open(filepath) as f:
        loaded = json.load(f)
    assert loaded["kpis"]["total_routes"]["value"] == 47
    assert loaded["kpis"]["total_vrfs"]["value"]   == 1
